+// isGitRepo checks whether the given path is inside a git repository.
+func isGitRepo(path string) bool {
+	cmd := exec.Command("git", "rev-parse", "--git-dir")
+	if path != "" {
+		cmd.Dir = path
+	}
+	return cmd.Run() == nil
+}
